import yaml, sys, re, os

with open('.kiln/tasks.yaml') as f:
    data = yaml.safe_load(f)

errors = []

# Check root is a list
if not isinstance(data, list):
    errors.append('Root is not a YAML sequence (list)')
    for e in errors:
        print(f'FAIL: {e}')
    sys.exit(1)

ids = set()
all_ids = {t.get('id') for t in data}

for i, task in enumerate(data):
    tid = task.get('id')
    prompt = task.get('prompt')
    needs = task.get('needs', [])
    if needs is None:
        needs = []

    # Check id
    if not tid:
        errors.append(f'Task {i}: missing id')
        continue
    if not re.match(r'^[a-z0-9]+(-[a-z0-9]+)*$', tid):
        errors.append(f'Task {i}: id \"{tid}\" fails kebab-case regex')
    if tid in ids:
        errors.append(f'Task {i}: duplicate id \"{tid}\"')
    ids.add(tid)

    # Check prompt path
    expected = f'.kiln/prompts/tasks/{tid}.md'
    if prompt != expected:
        errors.append(f'Task \"{tid}\": prompt \"{prompt}\" != \"{expected}\"')

    # Check prompt file exists
    if not os.path.isfile(prompt):
        errors.append(f'Task \"{tid}\": prompt file \"{prompt}\" does not exist')

    # Check needs references
    for dep in needs:
        if dep not in all_ids:
            errors.append(f'Task \"{tid}\": needs \"{dep}\" not found in task IDs')

# Check for cycles (topological sort)
graph = {}
for t in data:
    graph[t['id']] = t.get('needs', []) or []

visited = set()
rec_stack = set()
cycle_found = []

def dfs(node, path):
    visited.add(node)
    rec_stack.add(node)
    for dep in graph.get(node, []):
        if dep in rec_stack:
            cycle_found.append(' -> '.join(path + [dep]))
            return
        if dep not in visited:
            dfs(dep, path + [dep])
    rec_stack.remove(node)

for node in graph:
    if node not in visited:
        dfs(node, [node])

if cycle_found:
    for c in cycle_found:
        errors.append(f'Cycle detected: {c}')

if errors:
    print('VALIDATION FAILED:')
    for e in errors:
        print(f'  - {e}')
    sys.exit(1)
else:
    print(f'VALIDATION PASSED: {len(data)} tasks, no errors')
    print()
    print('Task graph:')
    for t in data:
        needs = t.get('needs', []) or []
        deps = ', '.join(needs) if needs else '(independent)'
        exists = 'OK' if os.path.isfile(t['prompt']) else 'MISSING'
        print(f'  {t[\"id\"]:25s} deps=[{deps:30s}]  file={exists}')
"

