import yaml, sys, re, os

with open('.kiln/tasks.yaml') as f:
    data = yaml.safe_load(f)

errors = []
all_ids = {t.get('id') for t in data}
ids = set()

for i, task in enumerate(data):
    tid = task.get('id')
    prompt = task.get('prompt')
    needs = task.get('needs', []) or []

    if not tid:
        errors.append(f'Task {i}: missing id')
        continue
    if not re.match(r'^[a-z0-9]+(-[a-z0-9]+)*$', tid):
        errors.append(f'Task \"{tid}\": bad id format')
    if tid in ids:
        errors.append(f'Task \"{tid}\": duplicate id')
    ids.add(tid)

    expected = f'.kiln/prompts/tasks/{tid}.md'
    if prompt != expected:
        errors.append(f'Task \"{tid}\": wrong prompt path')
    if not os.path.isfile(prompt):
        errors.append(f'Task \"{tid}\": MISSING file {prompt}')

    for dep in needs:
        if dep not in all_ids:
            errors.append(f'Task \"{tid}\": needs \"{dep}\" not defined')

# Cycle check
graph = {t['id']: t.get('needs', []) or [] for t in data}
visited = set()
rec_stack = set()
has_cycle = False
def dfs(n):
    global has_cycle
    visited.add(n); rec_stack.add(n)
    for dep in graph.get(n, []):
        if dep in rec_stack: has_cycle = True; return
        if dep not in visited: dfs(dep)
    rec_stack.remove(n)
for n in graph:
    if n not in visited: dfs(n)
if has_cycle: errors.append('Cycle detected in dependency graph')

if errors:
    print('FINAL VALIDATION FAILED:')
    for e in errors: print(f'  - {e}')
    sys.exit(1)
else:
    print(f'FINAL VALIDATION PASSED')
    print(f'  Tasks: {len(data)}')
    print(f'  Independent: {sum(1 for t in data if not (t.get(\"needs\") or []))}')
    print(f'  With deps:   {sum(1 for t in data if t.get(\"needs\"))}')
    print(f'  All files:   exist')
    print(f'  Cycles:      none')
    print(f'  Schema:      valid')
"
